{
  "name": "Demo User",
  "ouId": "{{demoOuId}}",
  "allowSelfRegistration": true,
  "schema": {
        "username": {
            "type": "string",
            "required": false,
            "unique": true
        },
        "sub": {
            "type": "string",
            "required": false,
            "unique": true
        },
        "email": {
            "type": "string",
            "required": false,
            "unique": true
        },
        "given_name": {
            "type": "string",
            "required": false
        },
        "family_name": {
            "type": "string",
            "required": false
        },
        "mobile_number": {
            "type": "string",
            "required": false
        },
        "userSource": {
            "type": "string",
            "required": false
        },
        "password": {
            "type": "string",
            "credential": true,
            "required": false
        }
    }
}

{
