{
    "name": "Demo App",
    "description": "Application to demonstrate app native login",
    "ouId": "{{demoOuId}}",
    "isRegistrationFlowEnabled": true,
    "allowedUserTypes": [
        "{{demoSchemaName}}"
    ],
    "assertion": {
        "issuer": "https://localhost:8090",
        "validityPeriod": 3600,
        "userAttributes": [
            "email",
            "username",
            "given_name",
            "family_name",
            "groups"
        ]
    },
    "inboundAuthConfig": [
        {
            "type": "oauth2",
            "config": {
                "clientId": "{{LOGIN_APPLICATION_CLIENT_ID}}",
                "redirectUris": [
                    "{{LOGIN_APPLICATION_REDIRECT_URI}}"
                ],
                "grantTypes": [
                    "authorization_code",
                    "refresh_token"
                ],
                "responseTypes": [
                    "code"
                ],
                "publicClient": true,
                "pkceRequired": true,
                "tokenEndpointAuthMethod": "none",
                "token": {
                    "accessToken": {
                        "userConfig": {
                        "validityPeriod": 7200,
                        "attributes": [
                            "email",
                            "username",
                            "given_name",
                            "family_name",
                            "groups"
                        ]
                    }
                    },
                    "idToken": {
                        "validityPeriod": 3600,
                        "userAttributes": [
                            "email",
                            "username",
                            "given_name",
                            "family_name",
                            "groups"
                        ],
                        "scopeClaims": {
                            "profile": [
                                "username",
                                "family_name",
                                "given_name"
                            ],
                            "email": [
                                "email"
                            ],
                            "group": [
                                "group"
                            ]
                        }
                    }
                }
            }
        }
    ]
}

{
    "name": "Demo Basic Authentication Flow",
    "handle": "demo-basic-flow",
    "flowType": "AUTHENTICATION",
    "nodes": [
        {
            "id": "start",
            "type": "START",
            "onSuccess": "prompt_credentials"
        },
        {
            "id": "prompt_credentials",
            "type": "PROMPT",
            "meta": {
                "components": [
                    {
                        "type": "TEXT",
                        "id": "text_001",
                        "label": "Sign In",
                        "variant": "HEADING_1"
                    },
                    {
                        "type": "BLOCK",
                        "id": "block_001",
                        "components": [
                            {
                                "id": "input_001",
                                "ref": "username",
                                "type": "TEXT_INPUT",
                                "label": "Username",
                                "required": true,
                                "placeholder": "Enter your username"
                            },
                            {
                                "id": "input_002",
                                "ref": "password",
                                "type": "PASSWORD_INPUT",
                                "label": "Password",
                                "required": true,
                                "placeholder": "Enter your password"
                            },
                            {
                                "type": "ACTION",
                                "id": "action_001",
                                "label": "Sign In",
                                "variant": "PRIMARY",
                                "eventType": "SUBMIT"
                            }
                        ]
                    }
                ]
            },
            "prompts": [
                {
                    "inputs": [
                        {
                            "ref": "input_001",
                            "identifier": "username",
                            "type": "TEXT_INPUT",
                            "required": true
                        },
                        {
                            "ref": "input_002",
                            "identifier": "password",
                            "type": "PASSWORD_INPUT",
                            "required": true
                        }
                    ],
                    "action": {
                        "ref": "action_001",
                        "nextNode": "basic_auth"
                    }
                }
            ]
        },
        {
            "id": "basic_auth",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "CredentialsAuthExecutor"
            },
            "onSuccess": "auth_assert"
        },
        {
            "id": "auth_assert",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "AuthAssertExecutor"
            },
            "onSuccess": "end"
        },
        {
            "id": "end",
            "type": "END"
        }
    ]
}

{
    "name": "Demo MFA Authentication Flow",
    "handle": "demo-mfa-flow",
    "flowType": "AUTHENTICATION",
    "nodes": [
        {
            "id": "start",
            "type": "START",
            "onSuccess": "prompt_credentials"
        },
        {
            "id": "prompt_credentials",
            "type": "PROMPT",
            "meta": {
                "components": [
                    {
                        "type": "TEXT",
                        "id": "text_001",
                        "label": "{{ t(signin:heading) }}",
                        "variant": "HEADING_1"
                    },
                    {
                        "type": "BLOCK",
                        "id": "block_001",
                        "components": [
                            {
                                "id": "input_001",
                                "ref": "username",
                                "type": "TEXT_INPUT",
                                "label": "{{ t(elements:fields.username.label) }}",
                                "required": true,
                                "placeholder": "{{ t(elements:fields.username.placeholder) }}"
                            },
                            {
                                "id": "input_002",
                                "ref": "password",
                                "type": "PASSWORD_INPUT",
                                "label": "{{ t(elements:fields.password.label) }}",
                                "required": true,
                                "placeholder": "{{ t(elements:fields.password.placeholder) }}"
                            },
                            {
                                "type": "ACTION",
                                "id": "action_001",
                                "label": "{{ t(elements:buttons.submit.text) }}",
                                "variant": "PRIMARY",
                                "eventType": "SUBMIT"
                            }
                        ]
                    }
                ]
            },
            "prompts": [
                {
                    "inputs": [
                        {
                            "ref": "input_001",
                            "identifier": "username",
                            "type": "TEXT_INPUT",
                            "required": true
                        },
                        {
                            "ref": "input_002",
                            "identifier": "password",
                            "type": "PASSWORD_INPUT",
                            "required": true
                        }
                    ],
                    "action": {
                        "ref": "action_001",
                        "nextNode": "basic_auth"
                    }
                }
            ]
        },
        {
            "id": "basic_auth",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "CredentialsAuthExecutor"
            },
            "onSuccess": "send_sms"
        },
        {
            "id": "send_sms",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "OTPExecutor",
                "mode": "generate"
            },
            "onSuccess": "sms_send"
        },
        {
            "id": "sms_send",
            "type": "TASK_EXECUTION",
            "properties": {
                "senderId": "{{messageNotificationSenderId}}"
            },
            "executor": {
                "name": "SMSExecutor"
            },
            "onSuccess": "prompt_otp"
        },
        {
            "id": "prompt_otp",
            "type": "PROMPT",
            "prompts": [
                {
                    "inputs": [
                        {
                            "ref": "input_002",
                            "identifier": "otp",
                            "type": "TEXT_INPUT",
                            "required": true
                        }
                    ],
                    "action": {
                        "ref": "action_001",
                        "nextNode": "verify_sms"
                    }
                }
            ]
        },
        {
            "id": "verify_sms",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "OTPExecutor",
                "mode": "verify"
            },
            "onSuccess": "auth_assert"
        },
        {
            "id": "auth_assert",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "AuthAssertExecutor"
            },
            "onSuccess": "end"
        },
        {
            "id": "end",
            "type": "END"
        }
    ]
}

{
    "name": "Demo Multi Option Authentication Flow",
    "handle": "demo-multi-option-flow",
    "flowType": "AUTHENTICATION",
    "nodes": [
        {
            "id": "start",
            "type": "START",
            "onSuccess": "prompt_credentials_or_choice"
        },
        {
            "id": "prompt_credentials_or_choice",
            "type": "PROMPT",
            "meta": {
                "components": [
                    {
                        "category": "DISPLAY",
                        "id": "text_001",
                        "label": "Login",
                        "type": "TEXT",
                        "variant": "HEADING_3"
                    },
                    {
                        "components": [
                            {
                                "category": "FIELD",
                                "id": "input_001",
                                "label": "{{ t(elements:fields.username.label) }}",
                                "placeholder": "{{ t(elements:fields.username.placeholder) }}",
                                "ref": "username",
                                "required": true,
                                "type": "TEXT_INPUT"
                            },
                            {
                                "category": "FIELD",
                                "id": "input_002",
                                "label": "{{ t(elements:fields.password.label) }}",
                                "placeholder": "{{ t(elements:fields.password.placeholder) }}",
                                "ref": "password",
                                "required": true,
                                "type": "PASSWORD_INPUT"
                            },
                            {
                                "category": "ACTION",
                                "eventType": "SUBMIT",
                                "id": "action_001",
                                "label": "{{ t(elements:buttons.submit.text) }}",
                                "type": "ACTION",
                                "variant": "PRIMARY"
                            }
                        ],
                        "id": "block_001",
                        "type": "BLOCK"
                    },
                    {
                        "category": "DISPLAY",
                        "id": "divider_001",
                        "label": "{{ t(signin:or) }}",
                        "type": "DIVIDER"
                    },
                    {
                        "category": "ACTION",
                        "components": [
                            {
                                "category": "ACTION",
                                "eventType": "NAVIGATE",
                                "id": "action_002",
                                "label": "{{ t(signin:use_google) }}",
                                "nextNode": "basic_auth",
                                "type": "ACTION",
                                "variant": "OUTLINED"
                            }
                        ],
                        "id": "block_002",
                        "type": "BLOCK"
                    }
                ]
            },
            "prompts": [
                {
                    "inputs": [
                        {
                            "ref": "input_001",
                            "type": "TEXT_INPUT",
                            "identifier": "username",
                            "required": true
                        },
                        {
                            "ref": "input_002",
                            "type": "PASSWORD_INPUT",
                            "identifier": "password",
                            "required": true
                        }
                    ],
                    "action": {
                        "ref": "action_001",
                        "nextNode": "basic_auth"
                    }
                },
                {
                    "action": {
                        "ref": "action_002",
                        "nextNode": "google_auth"
                    }
                }
            ]
        },
        {
            "id": "basic_auth",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "CredentialsAuthExecutor"
            },
            "onSuccess": "auth_assert"
        },
        {
            "id": "google_auth",
            "type": "TASK_EXECUTION",
            "properties": {
                "idpId": "{{googleIDPId}}"
            },
            "executor": {
                "name": "GoogleOIDCAuthExecutor",
                "inputs": [
                    {
                        "ref": "input_003",
                        "type": "TEXT_INPUT",
                        "identifier": "code",
                        "required": true
                    }
                ]
            },
            "onSuccess": "auth_assert"
        },
        {
            "id": "auth_assert",
            "type": "TASK_EXECUTION",
            "executor": {
                "name": "AuthAssertExecutor"
            },
            "onSuccess": "end"
        },
        {
            "id": "end",
            "type": "END"
        }
    ]
}

{
    "name": "Demo Basic Registration Flow",
