                                "required": true,
                                "placeholder": "{{ t(elements:fields.username.placeholder) }}"
                            },
                            {
                                "id": "input_002",
                                "ref": "password",
                                "type": "PASSWORD_INPUT",
                                "label": "{{ t(elements:fields.password.label) }}",
                                "required": true,
                                "placeholder": "{{ t(elements:fields.password.placeholder) }}"
                            },
                            {
                                "type": "ACTION",
                                "id": "action_001",
