                "components": [
                    {
                        "type": "TEXT",
                        "id": "text_002",
                        "label": "Additional Information",
                        "variant": "HEADING_2"
                    },
                    {
                        "type": "BLOCK",
                        "id": "block_002",
                        "components": [
                            {
                                "id": "input_003",
                                "ref": "given_name",
                                "type": "TEXT_INPUT",
                                "label": "First Name",
                                "required": false,
                                "placeholder": "Enter your first name"
                            },
                            {
                                "id": "input_004",
                                "ref": "family_name",
                                "type": "TEXT_INPUT",
                                "label": "Last Name",
                                "required": false,
                                "placeholder": "Enter your last name"
                            },
                            {
                                "id": "input_005",
                                "ref": "email",
                                "type": "TEXT_INPUT",
                                "label": "Email Address",
                                "required": true,
                                "placeholder": "Enter your email address"
                            },
                            {
                                "id": "input_006",
                                "ref": "mobile_number",
                                "type": "TEXT_INPUT",
                                "label": "Mobile Number",
                                "required": true,
                                "placeholder": "Enter your mobile number"
                            },
                            {
                                "type": "ACTION",
                                "id": "action_002",
                                "label": "Complete Registration",
                                "variant": "PRIMARY",
                                "eventType": "SUBMIT"
                            }
                        ]
                    }
                ]
            },
            "prompts": [
                {
                    "inputs": [
                        {
                            "ref": "input_003",
                            "identifier": "given_name",
                            "type": "TEXT_INPUT",
                            "required": false
                        },
                        {
                            "ref": "input_004",
                            "identifier": "family_name",
                            "type": "TEXT_INPUT",
                            "required": false
                        },
                        {
                            "ref": "input_005",
                            "identifier": "email",
                            "type": "TEXT_INPUT",
                            "required": true
                        },
                        {
                            "ref": "input_006",
                            "identifier": "mobile_number",
                            "type": "TEXT_INPUT",
                            "required": true
                        }
                    ],
                    "action": {
                        "ref": "action_002",
                        "nextNode": "provisioning"
